const ZONES  = [{"id": "LA_CONEJERA", "name": "La Conejera", "num": 1, "x": 58, "y": 14}, {"id": "TORCA_GUAYMARAL", "name": "Torca-Guaymaral", "num": 2, "x": 70, "y": 5}, {"id": "JABOQUE", "name": "Jaboque", "num": 3, "x": 41, "y": 31}, {"id": "JUAN_AMARILLO", "name": "Juan Amarillo", "num": 4, "x": 50, "y": 28}, {"id": "CORDOBA", "name": "C\u00f3rdoba", "num": 5, "x": 66, "y": 26}, {"id": "SANTA_MARIA", "name": "Santa Mar\u00eda del Lago", "num": 6, "x": 55, "y": 42}, {"id": "CAPELLANIA", "name": "Capellan\u00eda", "num": 7, "x": 41, "y": 47}, {"id": "TIBANICA", "name": "Tibanica", "num": 8, "x": 26, "y": 80}, {"id": "LA_VACA", "name": "La Vaca", "num": 9, "x": 28, "y": 61}, {"id": "MEANDRO_DEL_SAY", "name": "Meandro del Say", "num": 10, "x": 26, "y": 50}];

// Normalización nombre→ID
const H_MAP = {
  "TORCA-GUAYMARAL":"TORCA_GUAYMARAL","TORCA GUAYMARAL":"TORCA_GUAYMARAL",
  "TIBABUYES":"JUAN_AMARILLO","JUAN AMARILLO":"JUAN_AMARILLO",
  "CÓRDOBA":"CORDOBA","CORDOBA":"CORDOBA",
  "LA CONEJERA":"LA_CONEJERA",
  "JABOQUE":"JABOQUE",
  "CAPELLANÍA":"CAPELLANIA","CAPELLANIA":"CAPELLANIA",
  "TIBANICA":"TIBANICA",
  "SANTA MARÍA DEL LAGO":"SANTA_MARIA","SANTA MARIA DEL LAGO":"SANTA_MARIA",
  "MEANDRO DEL SAY":"MEANDRO_DEL_SAY",
  "LA VACA":"LA_VACA",
};

/* ══════════════ STATE ══════════════ */
let placed = {};          // humedal_id → card_id
let dragging = null;
let uploadedImg = null;
let communityCards = [];
try { communityCards = JSON.parse(localStorage.getItem('humedex_comm') || '[]'); } catch(e) {}

/* ══════════════ TABS ══════════════ */
function showTab(name, el) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  document.getElementById('screen-' + name).classList.add('active');
  el.classList.add('active');
  if (name === 'community') renderCommunity();
  if (name === 'dex') renderDex('all');
}

/* ══════════════ MAP INIT ══════════════ */
function initMap() {
  const wrap = document.getElementById('mapWrap');
  ZONES.forEach(z => {
    const div = document.createElement('div');
    div.className = 'wetland-zone';
    div.id = 'z-' + z.id;
    div.style.left = z.x + '%';
    div.style.top  = z.y + '%';
    div.dataset.id = z.id;
    div.innerHTML = `<div class="wetland-num">${z.num}</div><div class="wetland-name-label">${z.name}</div>`;
    div.addEventListener('dragover', e => { e.preventDefault(); div.classList.add('drag-over'); });
    div.addEventListener('dragleave', () => div.classList.remove('drag-over'));
    div.addEventListener('drop', e => handleDrop(e, div, z));
    wrap.appendChild(div);
  });
}

/* ══════════════ HAND ══════════════ */
function renderHand() {
  const g = document.getElementById('handGrid');
  g.innerHTML = '';
  CARDS.forEach(c => {
    const isPlaced = Object.values(placed).includes(c.id);
    const el = document.createElement('div');
    el.className = 'card' + (isPlaced ? ' placed' : '');
    el.draggable = !isPlaced;
    el.innerHTML = `<img src="${FRONTS[c.id]}" alt="${c.name}" draggable="false"><div class="card-rarity-dot dot-${c.rareza.replace(' ','-').replace('ú','u').replace('ó','o')}"></div>`;
    if (!isPlaced) {
      el.addEventListener('dragstart', e => { dragging = c.id; e.dataTransfer.effectAllowed='move'; setTimeout(()=>el.classList.add('dragging'),0); });
      el.addEventListener('dragend', () => { el.classList.remove('dragging'); dragging = null; });
    }
    el.addEventListener('click', () => openModal(c.id, false));
    g.appendChild(el);
  });
}

/* ══════════════ DROP ══════════════ */
function handleDrop(e, div, zone) {
  e.preventDefault();
  div.classList.remove('drag-over');
  if (!dragging) return;
  const card = CARDS.find(c => c.id === dragging);
  const cardHumes = card.humedales.map(h => H_MAP[h] || H_MAP[h.toUpperCase()] || h);
  const ok = cardHumes.includes(zone.id);

  // Remove from previous zone
  for (const [hid, cid] of Object.entries(placed)) {
    if (cid === dragging) {
      delete placed[hid];
      const prevZone = document.getElementById('z-' + hid);
      const prevData = ZONES.find(z => z.id === hid);
      if (prevZone && prevData) {
        prevZone.classList.remove('has-card');
        prevZone.innerHTML = `<div class="wetland-num">${prevData.num}</div><div class="wetland-name-label">${prevData.name}</div>`;
      }
      break;
    }
  }

  if (ok) {
    placed[zone.id] = dragging;
    div.innerHTML = `<img class="zone-card-thumb" src="${FRONTS[dragging]}" alt="${card.name}" title="${card.name}">`;
    div.classList.add('has-card');
    toast('✅ ¡Correcto! ' + card.name + ' vive en ' + zone.name);
  } else {
    div.classList.add('wrong-flash');
    setTimeout(() => div.classList.remove('wrong-flash'), 900);
    toast('❌ ' + card.name + ' no vive en ' + zone.name, true);
  }
  renderHand();
  updateScore();
}

function updateScore() {
  const n = Object.keys(placed).length;
  document.getElementById('scoreVal').textContent = n + ' / 10';
  document.getElementById('progressFill').style.width = (n * 10) + '%';
  if (n >= 10) document.getElementById('congratsBox').classList.add('show');
}

/* ══════════════ POKÉDEX ══════════════ */
let currentFilter = 'all';
function renderDex(filter) {
  currentFilter = filter;
  const g = document.getElementById('dexGrid');
  g.innerHTML = '';
  const list = filter === 'all' ? CARDS : CARDS.filter(c => c.tipo === filter);
  list.forEach(c => {
    const tClass = 't-' + c.tipo.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
    const el = document.createElement('div');
    el.className = 'dex-card';
    el.innerHTML = `<img src="${FRONTS[c.id]}" alt="${c.name}"><div class="dex-info"><div class="dex-num">${c.num}</div><div class="dex-name">${c.name}</div><span class="tipo-badge ${tClass}">${c.tipo}</span></div>`;
    el.addEventListener('click', () => openModal(c.id, false));
    g.appendChild(el);
  });
}
function filterDex(f, btn) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  renderDex(f);
}

/* ══════════════ MODAL ══════════════ */
function openModal(cardId, isCommunity, commData) {
  if (isCommunity) {
    document.getElementById('modalImg').src = commData.image || 'data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="280"><rect fill="%230d1e36" width="400" height="280"/><text x="200" y="155" text-anchor="middle" fill="%2338b0e0" font-size="80">🌿</text></svg>';
    document.getElementById('modalNum').textContent = commData.num;
    document.getElementById('modalName').textContent = commData.name;
    document.getElementById('modalSci').textContent = commData.sci || '';
    document.getElementById('modalDesc').textContent = commData.desc || '';
    document.getElementById('modalTags').innerHTML = 
      `<span class="modal-tag">🏷️ ${commData.tipo}</span>` +
      (commData.humedal ? `<span class="modal-tag">💧 ${commData.humedal}</span>` : '') +
      `<span class="modal-tag">⭐ ${commData.rareza}</span>` +
      `<span class="modal-tag">✏️ ${commData.author}</span>`;
  } else {
    const c = CARDS.find(x => x.id === cardId);
    document.getElementById('modalImg').src = BACKS[cardId] || FRONTS[cardId];
    document.getElementById('modalNum').textContent = c.num;
    document.getElementById('modalName').textContent = c.name;
    document.getElementById('modalSci').textContent = c.sci;
    document.getElementById('modalDesc').textContent = c.desc;
    document.getElementById('modalTags').innerHTML =
      `<span class="modal-tag">🏷️ ${c.tipo}</span>` +
      c.humedales.map(h => `<span class="modal-tag">💧 ${h}</span>`).join('') +
      `<span class="modal-tag">⭐ ${c.rareza}</span>`;
  }
  document.getElementById('cardModal').classList.remove('hidden');
}
function closeModal() { document.getElementById('cardModal').classList.add('hidden'); }

/* ══════════════ CREATOR ══════════════ */
function handleImg(e) {
  const file = e.target.files[0];
  if (!file) return;
  const r = new FileReader();
  r.onload = ev => {
    uploadedImg = ev.target.result;
    const pImg = document.getElementById('pImg');
    pImg.src = uploadedImg; pImg.style.display = 'block';
    document.getElementById('pPlaceholder').style.display = 'none';
    document.getElementById('uploadPrev').src = uploadedImg;
    document.getElementById('uploadPrev').style.display = 'block';
  };
  r.readAsDataURL(file);
}

const RAREZA_LABELS = {'comun':'Común','poco-comun':'Poco Común','raro':'Raro','legendario':'Legendario'};
function livePreview() {
  const num   = document.getElementById('f-num').value || '---';
  const name  = document.getElementById('f-name').value || 'Nombre de la especie';
  const sci   = document.getElementById('f-sci').value || 'Nombre científico';
  const hume  = document.getElementById('f-humedal').value;
  const desc  = document.getElementById('f-desc').value || 'Tu descripción aquí...';
  const rar   = document.getElementById('f-rareza').value;
  document.getElementById('pNum').textContent  = num;
  document.getElementById('pName').textContent = name;
  document.getElementById('pSci').textContent  = sci;
  document.getElementById('pHume').textContent = hume ? 'HUMEDAL: ' + hume.toUpperCase() : 'HUMEDAL: —';
  document.getElementById('pDesc').textContent = desc;
  const b = document.getElementById('pBadge');
  b.className = 'rarity-badge rb-' + rar;
  b.textContent = RAREZA_LABELS[rar];
}

function saveCard() {
  const name = document.getElementById('f-name').value.trim();
  if (!name) { toast('⚠️ Escribe el nombre de la especie', true); return; }
  const card = {
    id: Date.now(),
    num:    document.getElementById('f-num').value || '???',
    name,
    sci:    document.getElementById('f-sci').value,
    tipo:   document.getElementById('f-tipo').value,
    humedal:document.getElementById('f-humedal').value,
    rareza: document.getElementById('f-rareza').value,
    desc:   document.getElementById('f-desc').value,
    author: document.getElementById('f-author').value || 'Anónimo',
    image:  uploadedImg,
    at:     new Date().toISOString()
  };
  communityCards.unshift(card);
  try { localStorage.setItem('humedex_comm', JSON.stringify(communityCards)); } catch(e) {}
  toast('🎉 ¡Carta publicada en la comunidad!');
  clearForm();
}

function clearForm() {
  ['f-num','f-name','f-sci','f-humedal','f-desc','f-author'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('f-tipo').value = 'Ave';
  document.getElementById('f-rareza').value = 'comun';
  uploadedImg = null;
  document.getElementById('pImg').style.display = 'none';
  document.getElementById('pPlaceholder').style.display = 'block';
  document.getElementById('uploadPrev').style.display = 'none';
  livePreview();
}

/* ══════════════ COMMUNITY ══════════════ */
function renderCommunity() {
  const g = document.getElementById('commGrid');
  document.getElementById('commCount').textContent = communityCards.length + ' cartas';
  g.innerHTML = '';
  if (!communityCards.length) {
    g.innerHTML = `<div class="empty-state"><div class="empty-icon">🌱</div><p>¡Aún no hay cartas de la comunidad!<br>¡Ve a <strong>✨ Crear</strong> y sé el primero!</p></div>`;
    return;
  }
  communityCards.forEach(c => {
    const el = document.createElement('div');
    el.className = 'comm-card';
    el.innerHTML = c.image
      ? `<img class="comm-art" src="${c.image}" alt="${c.name}">`
      : `<div class="comm-art-placeholder">🦋</div>`;
    el.innerHTML += `<div class="comm-info"><div class="comm-name">${c.name}</div><div class="comm-meta">💧 ${c.humedal||'Humedal'} · ✏️ ${c.author}</div></div>`;
    el.addEventListener('click', () => openModal(null, true, c));
    g.appendChild(el);
  });
}

/* ══════════════ TOAST ══════════════ */
function toast(msg, isError=false) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast' + (isError ? ' error' : '') + ' show';
  clearTimeout(t._t);
  t._t = setTimeout(() => t.classList.remove('show'), 3000);
}

/* ══════════════ BOOT ══════════════ */
initMap();
renderHand();
renderDex('all');
livePreview();
